SELECT 
FROM repair_order

    AND status = #{status}
    AND priority = #{priority}
    AND owner_id = #{ownerId}

        AND id IN (SELECT order_id FROM order_process WHERE repairman_id = #{repairmanId})

    AND create_time >= #{startTime}
